vector<int> generatePrimes(int count) {
    vector<int> primes;
    int candidate = 2;
    while (primes.size() < count) {
        bool isPrime = true;
        for (int prime : primes) {
            if (candidate % prime == 0) {
                isPrime = false;
                break;
            }
        }
        if (isPrime) {
            primes.push_back(candidate);
        }
        candidate++;
    }
    return primes;
}

